parameters.jsCode:
return [{
  json: {
    employeeEmail: 'exec@company.com',
    employeeName: 'John Executive',
    request: 'Book travel to SF for conference next week',
    dates: {
      departure: '2026-03-05',
      return: '2026-03-08'
    },
    preferences: {
      airline: 'United',
      hotel: 'Marriott',
      class: 'business'
    }
  }
}];

const policy = {
  maxFlightCost: 1500,
  maxHotelCost: 400,
  requiresApproval: (cost) => cost > 1000,
  preferredAirlines: ['United', 'Delta', 'American'],
  hotelTier: 'business'
};

const request = $input.first().json;

// Check policy compliance
const issues = [];
if (!policy.preferredAirlines.includes(request.preferences?.airline)) {
  issues.push('Non-preferred airline selected');
}

return [{
  json: {
    ...request,
    policy,
    policyIssues: issues,
    estimatedCost: {
      flight: 1200,
      hotel: 350,
      total: 1550
    },
    requiresApproval: true
  }
}];

parameters.text:
=Travel Booking Request

Employee: {{ $json.employeeName }}
Trip: {{ $json.request }}
Dates: {{ $json.dates.departure }} - {{ $json.dates.return }}

Estimated Cost: ${{ $json.estimatedCost.total }}
Policy Issues: {{ $json.policyIssues.length > 0 ? $json.policyIssues.join(', ') : 'None' }}

One-Click Approval: Reply with APPROVE to book

parameters.notes:
=Cost: ${{ $json.estimatedCost.total }}
Status: Awaiting approval
Policy check: {{ $json.policyIssues.length > 0 ? 'Issues found' : 'Clean' }}

